// 计算显示的卡片（默认4排 = 12个，展开后显示全部）
const displayedCards = computed(() => {
  if (isExpanded.value) {
    return allModelCards
  }
  return allModelCards.slice(0, DEFAULT_VISIBLE_COUNT)
})

// 是否还有更多卡片
const hasMoreCards = computed(() => allModelCards.length > DEFAULT_VISIBLE_COUNT)

// 切换展开/收起状态
const toggleExpand = () => {
  isExpanded.value = !isExpanded.value
}
